import React, { useMemo, useState } from 'react';

import { Button, Input, Select, Modal, addToast } from '@linm-soft/common-components';

import { useAppDispatch } from '../../../store/hooks';

import { useVoucherInitData } from '../../../hooks/useVoucherInitData';

import { masterService } from '../../../services/master/masterService';

import type { CustomerDto, CustomerGroupDto } from '../../../services/master/models';

import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';

import { CatalogListPagination, useCatalogListPaging, CatalogCompanyTh, CatalogCompanyTd } from '../../../components/catalog';

import { CustomerForm } from '../../../components/dm/CustomerForm';

import {

  buildCustomerGroupSelectOptions,

  CUSTOMER_TYPE_LABELS,

} from '../../../utils/customerGroupTree';

import styles from '../../../styles/erpPage.module.css';

import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

import { selectPlaceholderClass } from '../../../utils/selectField';



const TEST_ID = 'dm-doi-tuong';



const DoiTuongPage: React.FC = () => {

  const dispatch = useAppDispatch();

  const [searchDraft, setSearchDraft] = useState('');

  const [search, setSearch] = useState('');

  const [customerGroupFilter, setCustomerGroupFilter] = useState('');

  const [customerGroups, setCustomerGroups] = useState<CustomerGroupDto[]>([]);

  const [items, setItems] = useState<CustomerDto[]>([]);

  const [totalCount, setTotalCount] = useState(0);

  const [loading, setLoading] = useState(false);

  const [modalOpen, setModalOpen] = useState(false);

  const [editing, setEditing] = useState<CustomerDto | null>(null);

  const [deleteCustomerId, setDeleteCustomerId] = useState<string | null>(null);

  const [reloadKey, setReloadKey] = useState(0);



  const { customerGroupOptions: listGroupOptions } = useVoucherInitData('customer-list');

  const initFormName = modalOpen && editing ? 'edit-customer' : 'create-customer';



  const groupOpts = useMemo(() => {

    if (listGroupOptions.length > 0) return listGroupOptions;

    return buildCustomerGroupSelectOptions(customerGroups);

  }, [listGroupOptions, customerGroups]);



  const filterGroupOpts = useMemo(() => {

    if (listGroupOptions.length > 0) return listGroupOptions;

    return buildCustomerGroupSelectOptions(customerGroups);

  }, [listGroupOptions, customerGroups]);



  const groupById = useMemo(() => {

    const map = new Map<string, CustomerGroupDto>();

    for (const g of customerGroups) map.set(g.customerGroupId, g);

    return map;

  }, [customerGroups]);



  const groupLabel = (customerGroupId?: string) => {

    if (!customerGroupId) return '—';

    const g = groupById.get(customerGroupId);

    return g ? `${g.code} — ${g.name}` : '—';

  };



  const typeLabel = (customerGroupId?: string, customerType?: string) => {

    const g = customerGroupId ? groupById.get(customerGroupId) : undefined;

    const t = g?.customerType ?? customerType;

    return t ? (CUSTOMER_TYPE_LABELS[t] ?? t) : '—';

  };



  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();



  const handleSearch = () => {

    setSearch(searchDraft.trim());

    resetPage();

  };

  const refresh = () => setReloadKey(k => k + 1);



  React.useEffect(() => {

    let cancelled = false;

    const t = setTimeout(() => {

      masterService.getCustomerGroups({ page: 1, pageSize: 500 })

        .then(data => { if (!cancelled) setCustomerGroups(data.items); })

        .catch(() => { /* non-blocking */ });

    }, 0);

    return () => { cancelled = true; clearTimeout(t); };

  }, [reloadKey]);



  React.useEffect(() => {

    let cancelled = false;

    setLoading(true);

    const t = setTimeout(() => {

      masterService.getCustomers({

        search: search || undefined,

        customerGroupId: customerGroupFilter || undefined,

        page,

        pageSize,

      })

        .then(data => {

          if (!cancelled) {

            setItems(data.items);

            setTotalCount(data.totalCount);

          }

        })

        .catch(err => {

          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải danh mục đối tượng', type: 'error' }));

        })

        .finally(() => { if (!cancelled) setLoading(false); });

    }, 0);

    return () => { cancelled = true; clearTimeout(t); };

  }, [search, customerGroupFilter, page, pageSize, reloadKey, dispatch]);



  const openAdd = () => {

    setEditing(null);

    setModalOpen(true);

  };



  const openEdit = (row: CustomerDto) => {

    setEditing(row);

    setModalOpen(true);

  };



  const handleDelete = async (customerId: string) => {

    try {

      await masterService.deleteCustomer(customerId);

      dispatch(addToast({ message: 'Xóa đối tượng thành công', type: 'success' }));

      setDeleteCustomerId(null);

      setReloadKey(k => k + 1);

    } catch (err: unknown) {

      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));

    }

  };



  return (

    <div className={styles.page}>

      <div className={styles.pageHeader}>

        <div className={styles.titleBlock}>

          <h1 className={styles.title}><i className="fas fa-handshake" /> Danh mục đối tượng</h1>

        </div>

        <div className={styles.headerActions}>

          <Button variant="primary" onClick={openAdd} disabled={groupOpts.length === 0} data-testid={`${TEST_ID}-add-btn`}>

            <i className="fas fa-plus" /> Thêm đối tượng

          </Button>

        </div>

      </div>



      <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>

        <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>

          <Input

            placeholder="Tìm mã, tên..."

            value={searchDraft}

            onChange={e => setSearchDraft(e.target.value)}

            onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}

          />

        </div>

        <div className={styles.field} data-testid={`${TEST_ID}-field-customerGroupFilter`}>

          <Select

            value={customerGroupFilter}

            placeholder="Tất cả nhóm"

            className={selectPlaceholderClass(customerGroupFilter)}

            onChange={e => { setCustomerGroupFilter(e.target.value); resetPage(); }}

            options={filterGroupOpts}

          />

        </div>

        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch={true} />

      </div>



      <div className={styles.tableCard}>

        {loading ? (

          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>

        ) : items.length === 0 ? (

          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>

        ) : (

          <div className={styles.tableWrapper}>

            <table className={styles.table}>

              <thead>

                <tr>

                  <th>Mã</th>

                  <th>Tên đối tượng</th>

                  <CatalogCompanyTh />

                  <th>Nhóm</th>

                  <th>Loại</th>

                  <th>Mã số thuế</th>

                  <th>SĐT</th>

                  <th>TT</th>

                  <th className={styles.colActions} />

                </tr>

              </thead>

              <tbody>

                {items.map(r => (

                  <tr key={r.customerId}>

                    <td><code>{r.code}</code></td>

                    <td>{r.name}</td>

                    <CatalogCompanyTd companyId={r.companyId} />

                    <td>{groupLabel(r.customerGroupId)}</td>

                    <td><span className={styles.tagDefault}>{typeLabel(r.customerGroupId, r.customerType)}</span></td>

                    <td>{r.taxCode ?? '—'}</td>

                    <td>{r.phone ?? '—'}</td>

                    <td>

                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>

                        {r.isActive ? 'Dùng' : 'Ngưng'}

                      </span>

                    </td>

                    <td className={styles.colActions}>

                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">

                        <i className="fas fa-edit" />

                      </button>

                      <button

                        type="button"

                        className={`${styles.actionBtn} ${styles.actionBtnDanger}`}

                        onClick={() => setDeleteCustomerId(r.customerId)}

                        title="Xóa"

                      >

                        <i className="fas fa-trash" />

                      </button>

                    </td>

                  </tr>

                ))}

              </tbody>

            </table>

          </div>

        )}

        {!loading && (

          <CatalogListPagination

            testIdPrefix={TEST_ID}

            page={page}

            totalCount={totalCount}

            pageSize={pageSize}

            onPageChange={setPage}

            onPageSizeChange={setPageSize}

          />

        )}

      </div>



      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Sửa đối tượng' : 'Thêm đối tượng'}>

        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>

          {modalOpen && (

            <CustomerForm

              key={editing?.customerId ?? 'create'}

              testIdPrefix={TEST_ID}

              editing={editing}

              initFormName={initFormName}

              listGroupOptions={listGroupOptions}

              companyId={editing?.companyId}

              onCancel={() => setModalOpen(false)}

              onSaved={() => {

                setModalOpen(false);

                setReloadKey(k => k + 1);

              }}

              onValidationFailed={() => scrollToFirstFieldError(TEST_ID)}

            />

          )}

        </div>

      </Modal>



      <Modal isOpen={deleteCustomerId != null} onClose={() => setDeleteCustomerId(null)} title="Xác nhận xóa">

        <p>Bạn có chắc muốn xóa đối tượng này?</p>

        <div className={styles.modalActions}>

          <Button variant="secondary" onClick={() => setDeleteCustomerId(null)}>Hủy</Button>

          <Button

            variant="primary"

            onClick={() => deleteCustomerId != null && handleDelete(deleteCustomerId)}

          >

            Xóa

          </Button>

        </div>

      </Modal>

    </div>

  );

};



export default DoiTuongPage;

